#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e6+5;
LL T,a,p,fcnt,f[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Fenj(LL num){
    fcnt=0;
    for(LL x=2;x*x<=num;x++){
        if(num%x!=0)continue;
        f[++fcnt]=x;
        while(num%x==0)num/=x;
    }if(num>1)f[++fcnt]=num;
    return;
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
bool Is_pr(LL x,LL n){
    if(QP(x,n-1,n)!=1)return 0;
    for(int i=1;i<=fcnt;i++)
        if(QP(x,(n-1)/f[i],n)==1)return 0;
    return 1;
}
int main(){
    T=read();
    while(T--){
        a=read(),p=read();
        Fenj(p-1);
        if(Is_pr(a,p))cout<<"Yes\n";
        else cout<<"No\n";
    }
    return 0;
}
